def smallest_change(arr):
    """
    Given an array arr of integers, find the minimum number of elements that
    need to be changed to make the array palindromic. A palindromic array is an array that
    is read the same backwards and forwards. In one change, you can change one element to any other element.

    For example:
    smallest_change([1,2,3,5,4,7,9,6]) == 4
    smallest_change([1, 2, 3, 4, 3, 2, 2]) == 1
    smallest_change([1, 2, 3, 2, 1]) == 0
    """

    # O(n)
    def is_palindromic(s):
        return s == s[::-1]

    # O(n)
    def find_min(i):
        # Base case
        if i >= len(arr):
            return 0

        # Recursive case
        # If the element is already palindromic,
        # skip it and move to the next element.
        if is_palindromic(str(arr[i])):
            return find_min(i + 1)
        else:
            # If the element is not palindromic,
            # change it to a palindromic number
            # and return 1 for the change.
            arr[i] = int(str(arr[i])[::-1])
            return 1 + find_min(i + 1)

    return find_min(0)

