def maximum(arr, k):
    """
    Given an array arr of integers and a positive integer k, return a sorted list 
    of length k with the maximum k numbers in arr.

    Example 1:

        Input: arr = [-3, -4, 5], k = 3
        Output: [-4, -3, 5]

    Example 2:

        Input: arr = [4, -4, 4], k = 2
        Output: [4, 4]

    Example 3:

        Input: arr = [-3, 2, 1, 2, -1, -2, 1], k = 1
        Output: [2]

    Note:
        1. The length of the array will be in the range of [1, 1000].
        2. The elements in the array will be in the range of [-1000, 1000].
        3. 0 <= k <= len(arr)
    """

    # Time complexity: O(n * log(k)) where n is the length of arr
    # Space complexity: O(k)
    def partition(arr, low, high):
        pivot = arr[high]
        i = low
        for j in range(low, high):
            if arr[j] < pivot:
                arr[i], arr[j] = arr[j], arr[i]
                i += 1
        arr[i], arr[high] = arr[high], arr[i]
        return i

    def find_k_largest_helper(arr, low, high, k):
        if low == high:
            return arr[:k]
        pivot_idx = partition(arr, low, high)
        if pivot_idx + 1 > k:
            return find_k_largest_helper(arr, low, pivot_idx - 1, k)
        elif pivot_idx + 1 < k:
            return find_k_largest_helper(arr, pivot_idx + 1, high, k)
        else:
            return arr[:k]

    return find_k_largest_helper(arr, 0, len(arr) - 1, k)

